llm_text:
You're super close! Main issues to fix:

- Typo: obstacleGird → obstacleGrid
- m, n are rows, cols (you had them swapped in places)
- Don't prefill 1s on the borders; obstacles break those runs
- Base cases: if start/end is an obstacle → 0
- Use the obstacle grid to zero out paths

Here are two correct solutions.

2D DP (clear & close to your code)

from typing import List

class Solution:
    def uniquePathsWithObstacles(self, obstacleGrid: List[List[int]]) -> int:
        m, n = len(obstacleGrid), len(obstacleGrid[0])
        if obstacleGrid[0][0] == 1 or obstacleGrid[m-1][n-1] == 1:
            return 0

        dp = [[0] * n for _ in range(m)]
        dp[m-1][n-1] = 1  # one way to stay at the goal if not blocked

        # last row (go right only)
        for j in range(n-2, -1, -1):
            dp[m-1][j] = 0 if obstacleGrid[m-1][j] == 1 else dp[m-1][j+1]

        # last col (go down only)
        for i in range(m-2, -1, -1):
            dp[i][n-1] = 0 if obstacleGrid[i][n-1] == 1 else dp[i+1][n-1]

        # fill the rest
        for i in range(m-2, -1, -1):
            for j in range(n-2, -1, -1):
                if obstacleGrid[i][j] == 1:
                    dp[i][j] = 0
                else:
                    dp[i][j] = dp[i+1][j] + dp[i][j+1]

        return dp[0][0]

1D DP (same logic, O(n) space)

from typing import List

class Solution:
    def uniquePathsWithObstacles(self, obstacleGrid: List[List[int]]) -> int:
        m, n = len(obstacleGrid), len(obstacleGrid[0])
        dp = [0] * n
        for i in range(m):
            for j in range(n):
                if obstacleGrid[i][j] == 1:
                    dp[j] = 0
                elif i == 0 and j == 0:
                    dp[j] = 1
                else:
                    dp[j] += dp[j-1] if j > 0 else 0
        return dp[-1]

Pick either; both pass all cases. The 1D version is shorter and memory-friendly.

Below is a step-by-step guide and a complete example in Swift that shows how to implement a simple Tic-Tac-Toe game in a single ViewController using UIKit.

1. Set Up Storyboard:
- Drag 9 UIButtons in a 3x3 grid
- Drag 1 Reset UIButton
- (Optional) UILabel for status
- Assign tags 0–8 to buttons

2. Create Outlets and Actions:
- Create IBOutlet collection: tileButtons
- Create IBAction for tileTapped
- Create IBAction for resetGame

3. Full Swift Code:

import UIKit

class ViewController: UIViewController {

    @IBOutlet var tileButtons: [UIButton]!
    @IBOutlet weak var statusLabel: UILabel!

    var board = [Int](repeating: 0, count: 9)
    var currentPlayer = 1

    let winningCombinations = [
        [0,1,2],[3,4,5],[6,7,8],
        [0,3,6],[1,4,7],[2,5,8],
        [0,4,8],[2,4,6]
    ]

    override func viewDidLoad() {
        super.viewDidLoad()
        statusLabel.text = "X's turn"
    }

    @IBAction func tileTapped(_ sender: UIButton) {
        let tag = sender.tag

        if board[tag] == 0 {
            board[tag] = currentPlayer

            if currentPlayer == 1 {
                sender.setTitle("X", for: .normal)
                currentPlayer = 2
                statusLabel.text = "O's turn"
            } else {
                sender.setTitle("O", for: .normal)
                currentPlayer = 1
                statusLabel.text = "X's turn"
            }

            checkForWinner()
        }
    }

    func checkForWinner() {
        for combo in winningCombinations {
            let a = board[combo[0]]
            let b = board[combo[1]]
            let c = board[combo[2]]

            if a != 0 && a == b && b == c {
                statusLabel.text = (a == 1) ? "X wins!" : "O wins!"

                for button in tileButtons {
                    button.isEnabled = false
                }
                return
            }
        }

        if !board.contains(0) {
            statusLabel.text = "It's a draw!"
        }
    }

    @IBAction func resetGame(_ sender: UIButton) {
        board = [Int](repeating: 0, count: 9)
        currentPlayer = 1

        for button in tileButtons {
            button.isEnabled = true
            button.setTitle("", for: .normal)
        }

        statusLabel.text = "X's turn"
    }
}
